const fs = require("fs");
const path = require("path");

const packageRoot = path.resolve(__dirname, "..");
const moduleRoot = path.join(packageRoot, "node_modules", "stylis-plugin-rtl");
const sourceDir = path.join(moduleRoot, "src");
const sourceFile = path.join(sourceDir, "stylis-rtl.ts");

if (!fs.existsSync(moduleRoot)) {
  process.exit(0);
}

fs.mkdirSync(sourceDir, { recursive: true });

if (!fs.existsSync(sourceFile)) {
  fs.writeFileSync(
    sourceFile,
    [
      "// Generated by GF-Shield to satisfy react-scripts source-map-loader.",
      "// stylis-plugin-rtl publishes source maps that reference this file,",
      "// but the package tarball does not ship the original TypeScript source.",
      "export {};",
      "",
    ].join("\n"),
    "utf8"
  );
}
